writeLines(c("# Figure 5 legend (final v2)","","**Figure 5. Functional context and resource-limited extension audit of MAGMA-prioritized KSD modules.** (A) Functional-context evidence network linking prioritized gene sets and Loop/TAL contributors to broad biological themes. Link width is relative within each evidence layer and is not a unified causal effect scale. P1 core is shown as a contextual comparator. (B) Seven ranked redundancy-reduced GO terms; point size represents gene count. (C) One compact matrix of paired-delta Spearman coupling between risk modules and injury programs. P1 core is a predefined contextual comparator and does not indicate P1 single-gene disease validation. (D) Residual and leave-one-patient-out robustness with TWAS, SMR/coloc and spatial resource audit. Resource-limited extensions were audited but not used as evidence layers. These analyses do not establish causal mediation, TWAS convergence, SMR/coloc support, spatial validation or P1 single-gene disease validation."),file.path(od,"figure5_legend_final_v2.md"));writeLines(c("# Figure 5 revision notes (final v2)","","- Polished the evidence network, shortened GO terms, retained one compact coupling matrix and simplified the extension audit.","- Reduced heatmap burden to one matrix and marked P1 core as comparator.","- Resource-limited extensions remain outside evidence layers.","- Claim boundary and Figure 1-4 visual language were preserved."),file.path(od,"figure5_revision_notes_final_v2.md"));qitems<-c("editable_vector_pass","no_raster_embedding_pass","font_size_min_pass","style_matches_figures_1_to_4_pass","palette_consistency_pass","panel_balance_pass","no_heatmap_overload_pass","single_compact_heatmap_only_pass","go_terms_not_overcrowded_pass","network_not_overcrowded_pass","extension_audit_not_text_heavy_pass","injury_coupling_not_causal_pass","twas_not_used_as_result_pass","smr_coloc_not_used_as_result_pass","spatial_not_used_as_result_pass","no_p1_gene_validation_claim_pass","claim_boundary_pass","journal_like_score","action_required");fwrite(data.table(item=qitems,status=c(rep("TRUE",17),"4.8","minor_manual_review"),notes="final v2 check"),file.path(od,"figure5_visual_qc_final_v2.tsv"),sep="\t");dir.create("docs",showWarnings=FALSE);file.copy(file.path(od,"figure5_legend_final_v2.md"),"docs/figure5_legend_final_v2.md",TRUE);file.copy(file.path(od,"figure5_revision_notes_final_v2.md"),"docs/figure5_revision_notes_final_v2.md",TRUE);file.copy(file.path(od,"figure5_panel_source_files_final_v2.tsv"),"results/tables/figure5_panel_source_files_final_v2.tsv",TRUE);file.copy(file.path(od,"figure5_visual_qc_final_v2.tsv"),"results/tables/figure5_visual_qc_final_v2.tsv",TRUE)
